class Solution {
public:
    int bitwiseComplement(int n) {
        if (n == 0) return 1;
        int bits = 0;
        int m = n;
        while (m) {
            bits++;
            m >>= 1;
        }
        int mask = (1 << bits) - 1;
        return n ^ mask;
    }
};
```
